def last_Digit_Factorial(n):
    if n < 0:
        raise ValueError("Factorial is not defined for negative numbers")
    if n == 0 or n == 1:
        return 1

    # For n >= 5, factorial will always end with 0 because it contains factors 2 and 5
    if n >= 5:
        return 0

    # For n = 2, 3, 4, compute factorial directly
    result = 1
    for i in range(2, n + 1):
        result *= i

    return result % 10
